DROP POLICY config_own ON public.config;
CREATE POLICY config_own ON public.config FOR ALL USING (
  (user_id IS NOT NULL AND auth.uid() = user_id)
  OR (user_id IS NULL AND id = 1 AND auth.uid() IS NOT NULL)
) WITH CHECK (
  user_id IS NOT NULL AND auth.uid() = user_id
);

-- Se acesso for apenas service_role, nao precisa de policy (service_role bypassa RLS).
